import React, { Component } from 'react';
import Typist from 'react-typist';
import './greeting.css';

export default class Greeting extends Component {

  constructor(props) {
    super(props);

    this.generatePhrase = this.generatePhrase.bind(this);
    this.again = this.again.bind(this);

    this.state = {
      phrase_list: []
    }
  }

  componentDidMount() {
    this.generatePhrase();
  }

  again() {
    this.setState({ phrase_list: [] }, e => this.generatePhrase());
  }

  generatePhrase() {
    let plt = [];
    c_phrases.sort(() => Math.random() - 0.5);
    let i = 0;
    c_phrases.forEach(e => {
      e += "."
      plt.push(<span className="Phrase" key={i++}>{e}</span>);
      plt.push(<Typist.Backspace key={i++} count={e.length} delay={1000} />);
    });

    this.setState({ phrase_list: plt });
  }

  render() {
    let typing = undefined;
    if (this.state.phrase_list.length > 0) {
      typing = (
        <Typist
          onTypingDone={this.again}
          avgTypingDelay={100}
          cursor={{
            show: true,
            blink: true,
            element: '_',
            hideWhenDone: false,
            hideWhenDoneDelay: 1000,
          }}>
          {this.state.phrase_list}
        </Typist>
      );
    }


    return (
      <div className="Greeting">
        <span className="Iam">I am&nbsp;</span>
        {typing}
      </div>
    );
  }
}

const c_phrases = [
  "an engineer",
  "a developer",
  "a musician",
  "a researcher",
  "a traveler",
  "a husband",
  "a learner",
  "a student"
]