import React from 'react';
import './App.css';
import {
  BrowserRouter as Router,
  Switch,
  Route
} from "react-router-dom";

import Welcome from './apps/welcome/page/welcome/welcome';
import DontBreakChain from './apps/studio/dontbreakchain/page/dontbreakchain/dontbreakchain';

function App() {
  return (
    <div className="App">
      <div className="Curtain">
        <Router>
          <Switch>
            <Route path="/studio/dontbreakchain"><DontBreakChain /></Route>
            <Route path="/"><Welcome /></Route>
          </Switch>
        </Router>
      </div>
    </div>
  );
}

export default App;
